// Get all items from GitHub API
const items = $input.all();

// Group events by repository
const repoActivity = {};

for (const item of items) {
  const event = item.json;
  const repoName = event.repo?.name || 'Unknown repo';
  const eventType = event.type;
  const actor = event.actor?.login;
  const createdAt = event.created_at;

  if (!repoActivity[repoName]) {
    repoActivity[repoName] = {
      commits: [],
      issues: [],
      pullRequests: [],
      other: []
    };
  }

  // Categorize by event type
  if (eventType === 'PushEvent') {
    const commits = event.payload?.commits || [];
    for (const commit of commits) {
      repoActivity[repoName].commits.push({
        message: commit.message,
        author: commit.author?.name || actor,
        date: createdAt
      });
    }
  } else if (eventType === 'IssuesEvent') {
    repoActivity[repoName].issues.push({
      action: event.payload?.action,
      title: event.payload?.issue?.title,
      date: createdAt
    });
  } else if (eventType === 'PullRequestEvent') {
    repoActivity[repoName].pullRequests.push({
      action: event.payload?.action,
      title: event.payload?.pull_request?.title,
      date: createdAt
    });
  } else {
    repoActivity[repoName].other.push({
      type: eventType,
      date: createdAt
    });
  }
}

// Format into a clean text for Gemini
let activityText = '';

for (const [repo, activity] of Object.entries(repoActivity)) {
  activityText += `\n📁 REPO: ${repo}\n`;

  if (activity.commits.length > 0) {
    activityText += `  Commits (${activity.commits.length}):\n`;
    for (const c of activity.commits) {
      activityText += `    - "${c.message}" by ${c.author}\n`;
    }
  }

  if (activity.issues.length > 0) {
    activityText += `  Issues (${activity.issues.length}):\n`;
    for (const i of activity.issues) {
      activityText += `    - [${i.action}] ${i.title}\n`;
    }
  }

  if (activity.pullRequests.length > 0) {
    activityText += `  Pull Requests (${activity.pullRequests.length}):\n`;
    for (const pr of activity.pullRequests) {
      activityText += `    - [${pr.action}] ${pr.title}\n`;
    }
  }
}

// Return single item with formatted activity for Gemini
return [{
  json: {
    activity: activityText,
    totalEvents: items.length,
    reposCount: Object.keys(repoActivity).length,
    weekOf: new Date().toDateString()
  }
}];
